[Generic flatness, geometric form]
  \label{thm:generic_flatness}
  \lean{AlgebraicGeometry.genericFlatness}
  \uses{thm:generic_flatness_algebraic}
  % SOURCE: [Nitsure], \S4, Theorem ``generic flatness''
